// src/components/PreviewDirection.astro
---
import { ArrowLeftRight } from '@lucide/astro'

interface Props {
  src: string
}

const { src } = Astro.props
---

<preview-direction data-src={src}>
  <button
    type="button"
    aria-label="Toggle direction"
    aria-pressed="true"
    class="inline-flex items-center justify-center gap-2 rounded-md border border-gray-200 bg-white px-3 py-1.5 text-sm font-medium text-gray-900 transition-colors hover:bg-gray-50 disabled:pointer-events-none disabled:opacity-50"
  >
    <ArrowLeftRight class="size-4" />

    <span data-text>LTR</span>
  </button>
</preview-direction>

<script>
  class PreviewDirection extends HTMLElement {
    private contentSrc: string | null = null
    private isProcessing = false

    private clickHandler: (() => void) | null = null

    connectedCallback() {
      this.contentSrc = this.dataset.src || null

      if (!this.contentSrc) {
        return
      }

      const buttonEl = this.querySelector('button')

      if (!buttonEl) {
        return
      }

      const buttonText = buttonEl.querySelector('span[data-text]')

      if (!buttonText) {
        return
      }

      this.clickHandler = () => {
        if (this.isProcessing) {
          return
        }

        this.isProcessing = true

        const isLtr = buttonEl.getAttribute('aria-pressed') === 'true'
        const newState = !isLtr

        const iframeEl = document.querySelector<HTMLIFrameElement>(
          `component-preview[data-src="${this.contentSrc}"] iframe`,
        )

        if (iframeEl?.contentWindow) {
          const iframeOrigin = new URL(iframeEl.src, globalThis.location.href).origin

          iframeEl.contentWindow.postMessage(
            {
              type: 'hyperui:preview-direction',
              ltr: newState,
            },
            iframeOrigin,
          )
        }

        buttonEl.setAttribute('aria-pressed', String(newState))

        buttonText.textContent = newState ? 'LTR' : 'RTL'

        this.isProcessing = false
      }

      buttonEl.addEventListener('click', this.clickHandler)
    }

    disconnectedCallback() {
      const buttonEl = this.querySelector('button')

      if (buttonEl && this.clickHandler) {
        buttonEl.removeEventListener('click', this.clickHandler)

        this.clickHandler = null
      }
    }
  }

  customElements.define('preview-direction', PreviewDirection)
</script>

